# Title: Tools for using NASA Earthdata# Author: Jorrel Khalil S. Aunario# IRRI# License GPL3# Version 1, April 2025APPEARS_URL <- "https://appeears.earthdatacloud.nasa.gov/api/"DATAPOOL_PLATFORMS <- data.frame(  platform = c("ASTER GDEM", "Aqua MODIS", "Combined MODIS", "Terra MODIS", "Suomi NPP VIIRS", "ECOSTRESS", "MEaSUREs"),  subdirectory  = c("ASTT", "MOLA", "MOTA", "MOLT", "VIIRS", "ECOSTRESS", "MEASURES"),  stringsAsFactors = FALSE)earthdata.product <- function(product = NULL, update = TRUE) {  if (update || !file.exists(system.file("satproducts/earthdata.products.ref.json", package = "orysat")))  {    prod.info <- httr::GET(paste0(APPEARS_URL, "product"))    prod.info <- jsonlite::toJSON(httr::content(prod.info), auto_unbox = TRUE)    writeLines(prod.info, con = file.path(system.file("satproducts", package = "orysat"), "earthdata.products.ref.json"))  } else {    prod.info <- readLines(system.file("satproducts/earthdata.products.ref.json", package = "orysat"))  }  prod.info <- jsonlite::fromJSON(prod.info)  #prod.info <- setNames(split(prod.info, seq_len(nrow(prod.info))), prod.info$ProductAndVersion)  if (!is.null(product)) prod.info <- prod.info[grep(product, prod.info$ProductAndVersion), ]  prod.info}# On windows, the netrc file seem to work only when its in the working directory# On Linux, the netrc file should be in the home or root directoryearthdata.config <- function(netrc.file = ".netrc", user, password) {  if (!file.exists(netrc.file))    success <- try(writeLines(c("machine urs.earthdata.nasa.gov",                                paste("login", user),                                paste("password", password)),                              con = netrc.file), silent = TRUE)  else success <- TRUE  class(success) != "try-error"}
